#define MAXSIZE 100
int queue[MAXSIZE];
int front = -1;
int rear = -1;

// Check if queue is empty
int isEmpty() {
 return (front == -1);
}

// Check if queue is full
int isFull() {
 return ((rear + 1) % MAXSIZE == front);
}

// Enqueue operation
void enqueue(int element) {
 if (isFull()) {
 printf("Queue Overflow\n");
 return;
 }
 if (isEmpty()) {
 front = rear = 0;
 } else {
 rear = (rear + 1) % MAXSIZE;
 }
 queue[rear] = element;
}

// Dequeue operation
int dequeue() {
 int element;
 if (isEmpty()) {
 printf("Queue Underflow\n");
 return -1;
 }
 element = queue[front];
 if (front == rear) {
 front = rear = -1;
 } else {
 front = (front + 1) % MAXSIZE;
 }
 return element;
}

#define K 3 // Number of stacks
#define N 100 // Array size

int stackArray[N];
int top[K];

// Initialize tops for each stack
void initialize() {
 int i;
 int size = N / K;
 for (i = 0; i < K; i++) {
 top[i] = (i * size) - 1;
 }
}

// Push onto stack i
int push(int stackNum, int element) {
 int upperBound = ((stackNum + 1) * (N / K)) - 1;

 if (top[stackNum] >= upperBound) {
 printf("Stack %d Overflow\n", stackNum);
 return 0;
 }
 stackArray[++top[stackNum]] = element;
 return 1;
}

// Pop from stack i
int pop(int stackNum) {
 int lowerBound = stackNum * (N / K);

 if (top[stackNum] < lowerBound) {
 printf("Stack %d Underflow\n", stackNum);
 return -1;
 }
 return stackArray[top[stackNum]--];
}

struct Node {
 int data;
 struct Node* next;
};

struct Stack {
 struct Node* top;
};

struct Stack stacks[K]; // Array of K stacks

// Push onto stack i
void pushLinked(int stackNum, int element) {
 struct Node* newNode = (struct Node*)malloc(sizeof(struct Node));
 newNode->data = element;
 newNode->next = stacks[stackNum].top;
 stacks[stackNum].top = newNode;
}

// Pop from stack i
int popLinked(int stackNum) {
 if (stacks[stackNum].top == NULL) {
 printf("Stack %d Underflow\n", stackNum);
 return -1;
 }
 int element = stacks[stackNum].top->data;
 struct Node* temp = stacks[stackNum].top;
 stacks[stackNum].top = stacks[stackNum].top->next;
 free(temp);
 return element;
}

// Check if stack i is empty
int isEmptyLinked(int stackNum) {
 return (stacks[stackNum].top == NULL);
}
